class PostsSearch{constructor(){let e=this.searchPosts;document.getElementById("search-input").onkeyup=t=>{"Enter"===t.key&&e()},document.getElementById("search-icon").onkeyup=()=>{e()}}searchPosts(){let e=document.getElementById("search-input");if(e.value){let t=new URLSearchParams;t.set("tags",e.value),location.href=`/posts/?${t.toString()}`}}}export{PostsSearch};